{
  "verses": [
    {
      "n": 10,
      "column": "left",
      "text": "Un Jedïëta Behrni btja:\nBilans. Un Bilana Behrni bi-\nja: Jeus/ un Benjaminis/ un E-\nuds/ un Knaëns / un Setans/\nun Tarsis/ un Akisäirs.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Wiffi tchee irr Jedïaëta\nBehrni / to Tehwu Namma\nWirfneeki/ stipri warreni Lau-\ndis/ feptinvadeſmits tuhkfoschi\nun diwisints/ kas Rarrätsgahje.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Ir Supinis/ un Upims\nbtja Ira Behrni/ un Usims Ake-\nra Behrni.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Nawtaka Behrni btja:\nJakziels/ un Gunus/ un Jezers/\nun Sallums/ Villas Behrni.\n"
    },
    {
      "n": 14,
      "column": "left",
      "text": "Manaffus Behrni btja:\nEſriels/ kas winnam dsimme:\nun winna leeſa Seewa Arami-\nja dsemdeja tam Makiru Gile-\nada Tehwu.\n"
    },
    {
      "n": 15,
      "column": "left",
      "text": "Un Makirs nehme Upi-\nmam un Supimam Seewas/\nun winna Mahsai bija Maeka\nWahrda. Un ta ohtra Wahrs\ntja Zelaweads/ un Zelaweadam\nbija Meitas.\n"
    },
    {
      "n": 16,
      "column": "left",
      "text": "Un Makira Seewa Ma-\ncka dseindeja Dehlu/ un fauze\nwinna Wahrdu Peeres/ un win-\nna Brahta Wahrs bija Sarcs/\nun winna Dehla Wahrdi bija U-\nlams un Rakems.\n"
    },
    {
      "n": 17,
      "column": "left",
      "text": "Un llama Behrni btja :\nBedans. Schee bija Gileada\nBehrni/ ta Dehla Matira Ma-\nnaffus Dehla.\n"
    },
    {
      "n": 18,
      "column": "left",
      "text": "Un winna Mahsa Mole-\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Un Semida Behrni bija:\nAkejans/ un Sikeins/ un Likus/\nun Amians.\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "Un Eewaima Behrni bi-\nja: Sutelaks / un Bereds win-\nna Dehls / ta Dehls bija Ta-\nkats/ ta Dehls bija Eladus / ta\nDehls bija Takats.\n"
    },
    {
      "n": 21,
      "column": "right",
      "text": "Ta Dehls bija Sabads/\nta Dehls bija Sutelaks/ta Dehls\nbija Cesers un Eeleads. Un tee\nWihri no Gatas/ kas tai Sem-\nmê bija dsimmutchi/ nekawe\ntohs/ tapehz ka tee letja nahze\nwinnu Lohpus atxeint.\n"
    },
    {
      "n": 22,
      "column": "right",
      "text": "Un Eewaima winnu\nTehws sbehlojahs ilgu Laiku /\ntad nahze winna Brahti to ee-\npreezinaht.\n"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Pehz gabje tas pee fawas\nSeervas/ un ta tappe gruhta/ un\ndsemdeja weenu Dehlu/un nofan-\nze winna Wahrdn Brijus / ta-\npehz / ka Behdas bija winna\nNamnâ.\n"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Un winna Meita bija\nSeera/ ta ustaitija to Letjas un\nKalna Bet - Ohronu / un Usen\nSeera.\n"
    },
    {
      "n": 25,
      "column": "right",
      "text": "Un Repus bija winna\nDehls/ ta Dehls bija Reseps un\nTelus/ ta Dehls bija Tääus.\n"
    },
    {
      "n": 26,
      "column": "right",
      "text": "Ta Dehls bija Laëdans\nta Dehls bija Amjuds/ ta Dehl\nbija Eelisamus.\n"
    },
    {
      "n": 27,
      "column": "right",
      "text": "Ta Dehls bija Nuns/ ta\nDehls bija Josuüs.\n"
    },
    {
      "n": 28,
      "column": "right",
      "text": "Un winnu Dsihwoschan\nGgggg\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
